const AWS = require('aws-sdk');
const { execFile } = require('child_process');
const { promisify } = require('util');
const fs = require('fs').promises;
const path = require('path');
const crypto = require('crypto');

const s3 = new AWS.S3();
const execFileAsync = promisify(execFile);

const ALLOWED_FORMATS = ['jpg', 'jpeg', 'png', 'gif', 'webp', 'bmp', 'tiff'];
const MAX_FILE_SIZE = 50 * 1024 * 1024; // 50MB
const CONVERT_TIMEOUT = 30000; // 30 seconds

exports.handler = async (event) => {
  const tmpDir = '/tmp';
  let inputPath = null;
  let outputPath = null;

  try {
    for (const record of event.Records) {
      if (record.eventName.startsWith('ObjectCreated:')) {
        const bucket = record.s3.bucket.name;
        const key = decodeURIComponent(record.s3.object.key.replace(/\+/g, ' '));
        
        const outputFormat = record.s3.object.metadata?.outputFormat || 
                           record.s3.object.userMetadata?.outputFormat ||
                           'png';
        
        const normalizedFormat = outputFormat.toLowerCase().trim();
        
        if (!ALLOWED_FORMATS.includes(normalizedFormat)) {
          throw new Error(`Invalid output format: ${normalizedFormat}. Allowed formats: ${ALLOWED_FORMATS.join(', ')}`);
        }
        
        const sanitizedKey = path.basename(key);
        const randomId = crypto.randomBytes(16).toString('hex');
        inputPath = path.join(tmpDir, `${randomId}_input_${sanitizedKey}`);
        outputPath = path.join(tmpDir, `${randomId}_output.${normalizedFormat}`);
        
        const s3Object = await s3.getObject({ Bucket: bucket, Key: key }).promise();
        
        if (s3Object.ContentLength > MAX_FILE_SIZE) {
          throw new Error(`File size exceeds maximum allowed size of ${MAX_FILE_SIZE} bytes`);
        }
        
        await fs.writeFile(inputPath, s3Object.Body);
        
        const convertArgs = [
          inputPath,
          '-auto-orient',
          '-strip',
          '-quality', '85',
          '-resize', '2000x2000>',
          `${normalizedFormat}:${outputPath}`
        ];
        
        await execFileAsync('/opt/bin/convert', convertArgs, {
          timeout: CONVERT_TIMEOUT,
          maxBuffer: 10 * 1024 * 1024,
          env: {
            PATH: '/opt/bin',
            LD_LIBRARY_PATH: '/opt/lib',
            MAGICK_TMPDIR: tmpDir
          }
        });
        
        const convertedImage = await fs.readFile(outputPath);
        
        const outputKey = key.replace(/\.[^.]+$/, `.${normalizedFormat}`);
        
        await s3.putObject({
          Bucket: bucket,
          Key: outputKey,
          Body: convertedImage,
          ContentType: `image/${normalizedFormat === 'jpg' ? 'jpeg' : normalizedFormat}`,
          Metadata: {
            originalKey: key,
            convertedFormat: normalizedFormat
          }
        }).promise();
        
        console.log(`Successfully converted ${key} to ${outputKey}`);
      }
    }
    
    return {
      statusCode: 200,
      body: JSON.stringify({ message: 'Image conversion completed successfully' })
    };
    
  } catch (error) {
    console.error('Error processing image:', error);
    throw error;
    
  } finally {
    if (inputPath) {
      try {
        await fs.unlink(inputPath);
      } catch (err) {
        console.error('Error cleaning up input file:', err);
      }
    }
    
    if (outputPath) {
      try {
        await fs.unlink(outputPath);
      } catch (err) {
        console.error('Error cleaning up output file:', err);
      }
    }
  }
};